lm_before:
var (
	ErrNoMatch    = errors.New("no match location found")
	ErrEmptyAfter = errors.New("empty LLMAfter")
	ErrNoChange   = errors.New("no change between BaseText and LLMAfter")
)

lm_after:
var (
	// ErrNoMatch is returned when the alignment search fails to find a match
	ErrNoMatch    = errors.New("no match location found")
	// ErrEmptyAfter is returned when the LLMAfter field is empty
	ErrEmptyAfter = errors.New("empty LLMAfter")
	// ErrNoChange is returned when there is no difference between base and after texts
	ErrNoChange   = errors.New("no change between BaseText and LLMAfter")
)
